package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testIsNullStringSet() {
        // Given
        CSVFormat csvFormat = null;
        try {
            csvFormat = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                    Character.class, Character.class, boolean.class, boolean.class, String.class, String.class,
                    Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
                    boolean.class)
                    .newInstance(',', '\"', null, null, null, false, true, "\r\n", null, null, null, false, false,
                            false, false, false);
        } catch (Exception e) {
            e.printStackTrace();
        }

        // When
        boolean result = csvFormat.isNullStringSet();

        // Then
        assertEquals(false, result);
    }
}
